import requests
import json

url = "https://partner.shopeemobile.com/api/v2/video/edit_video_info?access_token=access_token&partner_id=partner_id&sign=sign&timestamp=timestamp&user_id=user_id"

payload=json.dumps({
  "video_upload_list": [
    {
      "allow_info": {
        "allow_duet": True,
        "allow_stitch": True
      },
      "caption": "this is a test video",
      "cover_image_url": "https://down-sg.img.susercontent.com/sg-11110199-6v99e-mgezdwct5eyya0_pack_v1_1000001_1",
      "item_info": [
        {
          "custom_item_name": "item display name",
          "item_id": 2
        }
      ],
      "scheduled_info": {
        "scheduled_post": True,
        "scheduled_post_time": 1761734929450
      },
      "video_upload_id": "sg-11110199-6v99e-mgezdwct5eyya0"
    }
  ]
})
headers = {
  'Content-Type': 'application/json'
}
response = requests.RPCRequest("POST",url,headers=headers, data=payload, allow_redirects=False)

print(response.text)
